			serviceName, _ := cmd.Flags().GetString("service-name")
			var svc binder.IBinder
			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "com.android.internal.statusbar.IStatusBar")
			}
			if err != nil {
				return err
			}

