			flagSysuiReceiverBinder, err := conn.GetService(ctx, flagSysuiReceiverName)
			if err != nil {
				return fmt.Errorf("resolving service %q for sysuiReceiver: %w", flagSysuiReceiverName, err)
			}
			var flagSysuiReceiver biometrics.IBiometricSysuiReceiver = biometrics.NewBiometricSysuiReceiverProxy(flagSysuiReceiverBinder)

			flagSensorIdsStr, err := cmd.Flags().GetString("sensorIds")
			if err != nil {
				return fmt.Errorf("reading flag sensorIds: %w", err)
			}
			var flagSensorIds []int32
			if flagSensorIdsStr != "" {
				for _, _s := range strings.Split(flagSensorIdsStr, ",") {
					_v, _err := strconv.ParseInt(strings.TrimSpace(_s), 0, 32)
					if _err != nil {
						return fmt.Errorf("invalid int32 in sensorIds: %w", _err)
					}
					flagSensorIds = append(flagSensorIds, int32(_v))
				}
			}

			flagCredentialAllowed, err := cmd.Flags().GetBool("credentialAllowed")
