			flagRequestId, err := cmd.Flags().GetInt64("requestId")
			if err != nil {
				return fmt.Errorf("reading flag requestId: %w", err)
			}

			err = svcProxy.ShowAuthenticationDialog(ctx, flagPromptInfo, flagSysuiReceiver, flagSensorIds, flagCredentialAllowed, flagRequireConfirmation, flagOperationId, flagRequestId)
